class Node:
    def __init__(self, data):
        self.left = None
        self.right = None
        self.data = data.lower()  # Ignore case sensitivity

def insert(root, data):
    if root is None:
        return Node(data)
    if data < root.data:
        root.left = insert(root.left, data)
    else:
        root.right = insert(root.right, data)
    return root

def inorder_traversal(root):
    if root:
        inorder_traversal(root.left)
        print(root.data, end=' ')
        inorder_traversal(root.right)

def process_string(s, index=0, root=None):
    if index >= len(s):
        return root
    char = s[index].lower()
    root = insert(root, char)
    return process_string(s, index + 1, root)

